import numpy as np
from collections import deque

def dbscan(X: np.ndarray, eps: float, min_samples: int) -> np.ndarray:
    n = len(X)
    labels = np.full(n, -1, dtype=int)
    visited = np.zeros(n, dtype=bool)
    cluster_id = 0

    def euclidean_neighbors(idx):
        neighbors = []
        for j in range(n):
            if np.sqrt(np.sum((X[idx] - X[j]) ** 2)) <= eps:
                neighbors.append(j)
        return neighbors

    for i in range(n):
        if visited[i]:
            continue
        visited[i] = True
        neighbors = euclidean_neighbors(i)

        if len(neighbors) < min_samples:
            # Noise (may later be reassigned as border point)
            labels[i] = -1
        else:
            # Start a new cluster
            labels[i] = cluster_id
            queue = deque(neighbors)

            while queue:
                j = queue.popleft()
                if not visited[j]:
                    visited[j] = True
                    j_neighbors = euclidean_neighbors(j)
                    if len(j_neighbors) >= min_samples:
                        queue.extend(j_neighbors)
                if labels[j] == -1:
                    labels[j] = cluster_id

            cluster_id += 1

    return labels
